export default {
  name: 'vueerror',
  data: function data() {
    return {
      timer: '',
      count: 0
    };
  },
  created: function created() {
    this.getTimes();
  },
  mounted: function mounted() {},
  methods: {
    getTimes: function getTimes() {
      var _this = this;

      this.timer = setInterval(function () {
        _this.count++;
        console.log('count', _this.count);
      }, 1000);
    }
  },
  beforeDestroy: function beforeDestroy() {
    if (this.timer) {
      console.log('count-destroy', this.count);
      clearInterval(this.timer);
    }
  }
};